import{_ as a,o as t,c as o,a6 as i}from"./chunks/framework.B6HGZFrS.js";const u=JSON.parse('{"title":"Release Workflow","description":"","frontmatter":{},"headers":[],"relativePath":"agent-instructions/release.md","filePath":"agent-instructions/release.md","lastUpdated":1781100822000}'),c={name:"agent-instructions/release.md"};function d(l,e,n,s,r,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="release-workflow" tabindex="-1">Release Workflow <a class="header-anchor" href="#release-workflow" aria-label="Permalink to “Release Workflow”">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>Use this file for versioning, documentation deployment, and npm/GitHub Packages publication tasks.</p><h2 id="strategy" tabindex="-1">Strategy <a class="header-anchor" href="#strategy" aria-label="Permalink to “Strategy”">​</a></h2><p>This project separates documentation deployment from package publication.</p><table tabindex="0"><thead><tr><th>Artifact</th><th>Trigger</th><th>Workflow</th><th>Result</th></tr></thead><tbody><tr><td>GitHub Pages docs</td><td>Push to <code>main</code> or manual dispatch</td><td><code>.github/workflows/deploy-docs.yml</code></td><td>Deploys latest <code>main</code> docs</td></tr><tr><td>Version bump</td><td>Push to <code>main</code> or manual dispatch</td><td><code>.github/workflows/version.yml</code></td><td>Updates <code>package.json</code>, <code>CHANGELOG.md</code>, and <code>docs/public/version.json</code></td></tr><tr><td>npm beta packages</td><td>Manual dispatch with <code>beta</code></td><td><code>.github/workflows/package.yml</code></td><td>Publishes core and MCP prerelease packages to the <code>beta</code> dist-tag</td></tr><tr><td>npm stable packages</td><td>Manual dispatch with <code>latest</code></td><td><code>.github/workflows/package.yml</code></td><td>Publishes core and MCP stable packages to the <code>latest</code> dist-tag</td></tr></tbody></table><h2 id="package-publication" tabindex="-1">Package Publication <a class="header-anchor" href="#package-publication" aria-label="Permalink to “Package Publication”">​</a></h2><ul><li>Standard package release is the GitHub Actions workflow <code>.github/workflows/package.yml</code>.</li><li>Package publication must be started manually with <code>workflow_dispatch</code>; pushes to <code>dev</code>, <code>main</code>, or <code>v*</code> tags must not publish npm packages automatically.</li><li>Version numbers use <code>&lt;manual&gt;.&lt;main&gt;.&lt;dev&gt;</code>: <ul><li><code>&lt;manual&gt;</code> is changed manually when the project needs a larger compatibility line.</li><li><code>&lt;main&gt;</code> is incremented by the stable version bump on <code>main</code>.</li><li><code>&lt;dev&gt;</code> is incremented by beta releases from <code>dev</code> and resets to <code>0</code> on the next stable bump.</li></ul></li><li>The stable version bump increments the main segment, resets the dev segment to <code>0</code>, and writes a numeric version such as <code>2.4.0</code>.</li><li><code>dev</code> branch publication reads local <code>package.json</code>, <code>origin/main</code>, npm <code>latest</code>, and npm <code>beta</code>, then publishes the next dev prerelease such as <code>2.4.1-beta.123.1</code> with npm dist-tag <code>beta</code>.</li><li>Stable publication must use the numeric <code>package.json</code> version and publishes with npm dist-tag <code>latest</code>.</li><li>Package publication includes <code>@sansenjian/qq-music-api</code> and <code>@sansenjian/qq-music-api-mcp</code>.</li><li>The MCP package version must match the core package version for stable releases.</li><li>Provide a tag only when intentionally publishing that historical stable tag.</li><li>Do not publish stable packages from <code>dev</code>; the workflow verifies <code>latest</code> releases come from <code>main</code>.</li><li>Do not use local <code>npm publish</code> as the normal release path unless the user explicitly asks for a manual/local publish test.</li></ul><h2 id="pre-release-validation" tabindex="-1">Pre-Release Validation <a class="header-anchor" href="#pre-release-validation" aria-label="Permalink to “Pre-Release Validation”">​</a></h2><p>Before triggering package publication, verify:</p><ul><li><code>npm run test</code></li><li><code>npm run lint</code></li><li><code>npm run build</code></li><li><code>npm run docs:build</code></li><li><code>package.json</code> version is the intended version.</li><li>The package workflow is manually dispatched with the intended <code>channel</code>.</li><li>Beta releases intentionally do not require committing the generated prerelease version.</li><li>Beta releases do not require syncing the latest stable version commit back into <code>dev</code>; the package workflow reads <code>origin/main</code>, npm <code>latest</code>, and npm <code>beta</code> to choose the prerelease base.</li><li>Beta releases, including manual dispatches, must run from the current <code>origin/dev</code> HEAD.</li><li><code>CHANGELOG.md</code> has been generated and reviewed when relevant.</li></ul><h2 id="workflow-behavior" tabindex="-1">Workflow Behavior <a class="header-anchor" href="#workflow-behavior" aria-label="Permalink to “Workflow Behavior”">​</a></h2><p>The package workflow checks out the selected ref, determines the release channel, installs dependencies, runs tests, runs lint, builds TypeScript, builds documentation, generates the changelog, then publishes to npm and GitHub Packages with the correct dist-tag.</p><p>Manual channel behavior:</p><ul><li>Manual dispatch with <code>channel=auto</code>: infer the channel from the selected ref.</li><li>Manual dispatch with <code>channel=beta</code> or <code>channel=latest</code>: use the requested channel, while preserving exact branch/tag safety checks.</li><li>Selecting the current <code>dev</code> ref with <code>channel=beta</code> publishes <code>beta</code>.</li><li>Selecting <code>main</code> or a <code>v*</code> tag on <code>main</code> with <code>channel=latest</code> publishes <code>latest</code>.</li></ul><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to “Verification”">​</a></h2><p>After publication, check:</p><ul><li>GitHub Actions run status under <code>actions/workflows/package.yml</code>.</li><li>npm package page for <code>@sansenjian/qq-music-api</code>.</li><li>npm package page for <code>@sansenjian/qq-music-api-mcp</code>.</li><li><code>npm dist-tag ls @sansenjian/qq-music-api</code> and <code>npm dist-tag ls @sansenjian/qq-music-api-mcp</code> show beta releases under <code>beta</code> and stable releases under <code>latest</code>.</li><li>GitHub Packages entry for this repository.</li></ul>',18)])])}const m=a(c,[["render",d]]);export{u as __pageData,m as default};
